-- Tabela de Clientes
CREATE TABLE CLIENTES (
    ID_CLIENTE         NUMBER         PRIMARY KEY,
    NOME               VARCHAR2(100)  NOT NULL,
    CIDADE             VARCHAR2(50)   NOT NULL,
    PAIS               VARCHAR2(50)   NOT NULL
);

-- Tabela de Pedidos
CREATE TABLE PEDIDOS (
    ID_PEDIDO          NUMBER         PRIMARY KEY,
    PRIORIDADE_PEDIDO  VARCHAR2(30)   NOT NULL,
    QUANTIDADE_PEDIDO  NUMBER         NOT NULL,
    VALOR_FRENTE       NUMBER(10,2),
    MODO_ENVIO         VARCHAR2(30)
);

-- Tabela de Vendas
CREATE TABLE VENDAS (
    ID_LINHA_PEDIDO          NUMBER          PRIMARY KEY,
    ID_PEDIDO                NUMBER          NOT NULL,
    ID_CLIENTE               NUMBER          NOT NULL,
    CATEGORIA_PRODUTO        VARCHAR2(50)    NOT NULL,
    SUBCATEGORIA_PRODUTO     VARCHAR2(50),
    EMBALAGEM_PRODUTO        VARCHAR2(30),
    LUCRO                    NUMBER(10,2),
    VALOR                    NUMBER(10,2),
    DESCONTO                 NUMBER(5,2),
    PRECO_BRUTO_UNIDADE      NUMBER(10,2),
    DATA_ENVIO               DATE,
    DATA_PEDIDO              DATE,
    FOREIGN KEY (ID_PEDIDO)  REFERENCES PEDIDOS(ID_PEDIDO),
    FOREIGN KEY (ID_CLIENTE) REFERENCES CLIENTES(ID_CLIENTE)
);








